final:
module four_bit_counter(  
    input clk,  
    input reset,  
    output reg [3:0] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset)  
            count <= 4'b0000;  
        else  
            count <= count + 1;  
    end  
  always @(*) begin
    if (1'b0) begin
      count <= count - 1;
    end
  end

endmodule
